// --- Inputs ---
// Define the lengths for the two moving averages
fastLength = input.integer(10, title="Fast SMA Length")
slowLength = input.integer(30, title="Slow SMA Length")

// --- Calculations ---
// Calculate the Simple Moving Averages
fastMA = ta.sma(close, fastLength)
slowMA = ta.sma(close, slowLength)

// --- Crossover Conditions ---
// Buy condition: Fast MA crosses above the Slow MA
buyCondition = ta.crossover(fastMA, slowMA)

// Sell condition: Fast MA crosses below the Slow MA
sellCondition = ta.crossunder(fastMA, slowMA)

// --- Strategy Execution ---
